            const overallAvgScore = overallAvg.reduce((a, b) => a + b, 0) / overallAvg.length;
            const diff = orgAvgScore - overallAvgScore;

            document.getElementById('org-avg-score').textContent = formatNumber(orgAvgScore, 1);
            document.getElementById('overall-diff').textContent =
