        // 2. 17개 역량 비교 차트
        function renderCompetencyChart() {
            const ctx = document.getElementById('competencyChart').getContext('2d');

            const labels = reportData.metadata.competency_list;
            const orgData = labels.map(comp => reportData.organization_averages[comp]);
            const overallData = labels.map(comp => reportData.overall_averages[comp]);

            new Chart(ctx, {
                type: 'bar',
                data: {
                    labels: labels,
                    datasets: [
                        {
                            label: '조직 평균',
                            data: orgData,
                            backgroundColor: 'rgba(165, 0, 52, 0.8)',
                            borderColor: 'rgba(165, 0, 52, 1)',
                            borderWidth: 1
                        },
                        {
                            label: 'PRI 평균',
                            data: overallData,
                            backgroundColor: 'rgba(156, 163, 175, 0.8)',
                            borderColor: 'rgba(156, 163, 175, 1)',
                            borderWidth: 1
                        }
                    ]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        y: {
                            beginAtZero: false,
                            min: 50,
                            max: 100,
                            ticks: {
                                stepSize: 10
                            },
                            title: {
                                display: true,
                                text: '점수'
                            }
                        },
                        x: {
                            ticks: {
                                autoSkip: false,
                                maxRotation: 45,
                                minRotation: 45
                            }
                        }
                    },
                    plugins: {
                        legend: {
                            position: 'top',
                        },
                        title: {
                            display: false
                        },
                        tooltip: {
                            callbacks: {
                                afterLabel: function(context) {
                                    const comp = context.label;
                                    const diff = reportData.differences[comp];
                                    return `차이: ${diff > 0 ? '+' : ''}${formatNumber(diff, 2)}`;
                                }
                            }
                        }
                    }
                }
            });
        }

        // 3. 리더별 강점유형 분류 테이블
        function renderMemberTable() {
            const tbody = document.getElementById('memberTableBody');
            const members = reportData.members_info || [];

            // 유형(코드) 순으로 정렬
            const sortedMembers = [...members].sort((a, b) => {
                // 유형 코드 알파벳 순으로 정렬
                return a.strength_type_code.localeCompare(b.strength_type_code);
            });

            sortedMembers.forEach(member => {
                const row = document.createElement('tr');
                row.innerHTML = `
                    <td class="px-4 py-3 whitespace-nowrap text-sm text-gray-900">${member.employee_id}</td>
                    <td class="px-4 py-3 whitespace-nowrap text-sm font-medium text-gray-900">${member.name}</td>
                    <td class="px-4 py-3 whitespace-nowrap text-sm text-gray-700">${member.position}</td>
                    <td class="px-4 py-3 whitespace-nowrap text-sm text-gray-700">${member.team}</td>
                    <td class="px-4 py-3 whitespace-nowrap">
                        <span class="px-3 py-1 inline-flex text-xs leading-5 font-semibold rounded-full bg-purple-100 text-purple-800">
                            ${member.strength_type_code}
                        </span>
                    </td>
                    <td class="px-4 py-3 text-sm text-gray-700">${member.strength_type_name}</td>
                `;
                tbody.appendChild(row);
            });
        }

